const { DISCOVERY_MANIFEST_FILE_PATH } = require('../../constants/manifest');
const { writeJsonFile, readJsonFile } = require('./json-file');

/**
 * @typedef { keyof typeof import('../../constants/device').DEVICE_TYPES } DeviceType
 * @typedef { import('../../page/paths').Paths } Paths
 * @typedef { { [device in DeviceType]?: Paths } } PagePathsByDevice
 * @typedef {import('../../page/navigable-page').NavigablePage} NavigablePage
 *
 * @typedef { object } DiscoveredNordicPages
 * @property { boolean } hasBuild
 * @property { string | undefined } baseHooksFile
 * @property { NavigablePage[] } discoveredNavigablePages
 * @property { { [statusError: string]: { paths: PagePathsByDevice } } } discoveredHttpErrorPages
 */

/**
 * @returns { DiscoveredNordicPages | {} } Discovery pages manifest content
 */
const readDiscoveryManifest = () => readJsonFile(DISCOVERY_MANIFEST_FILE_PATH);

/**
 * @param { DiscoveredNordicPages } discoveredPages
 */
const writeDiscoveryManifest = (discoveredPages) => {
  try {
    writeJsonFile(DISCOVERY_MANIFEST_FILE_PATH, discoveredPages);
  } catch (e) {
    throw new Error(
      'An error occurred while trying to write the Nordic Pages manifest:\n' +
        `${e.message}`,
    );
  }
};

module.exports = {
  readDiscoveryManifest,
  writeDiscoveryManifest,
};
